            businessMember = businessMember1,
            minOrders = 2,
            maxOrders = 2,
            minServicesPerOrder = 1,
            maxServicesPerOrder = 2,
            minProductsPerOrder = 0, // No products
            maxProductsPerOrder = 0
        )

        val productsOnly = newCommissionReportLineItems(
            businessMember = businessMember2,
            minOrders = 2,
            maxOrders = 2,
            minServicesPerOrder = 0, // No services
            maxServicesPerOrder = 0,
            minProductsPerOrder = 1,
            maxProductsPerOrder = 2
        )

        val both = newCommissionReportLineItems(
            businessMember = businessMember3,
            minOrders = 2,
            maxOrders = 2,
            minServicesPerOrder = 1,
            maxServicesPerOrder = 2,
            minProductsPerOrder = 1,
            maxProductsPerOrder = 2
        )

        val allLineItems = servicesOnly + productsOnly + both
        val reports = allLineItems.groupBy { it.businessMemberToken }
            .map { (_, items) -> CommissionReport(items, emptyList()) }

        val workbook = reports.toExcelWorkbook()
        val summarySheet = workbook.sheet("Summary")

        val serviceSummaryHeader = summarySheet.header("Service Commissions")
        val productSummaryHeader = summarySheet.header("Product Commissions")

        // Collect all business member names from service section
        val serviceBusinessMembers = mutableSetOf<String>()
        for (i in (serviceSummaryHeader.rowNum + 1) until summarySheet.lastRowNum) {
            val row = summarySheet.getRow(i) ?: continue
            val cellValue = try {
                row.getCell(0)?.stringCellValue
            } catch (e: Exception) {
                null
            }
            // Stop when we hit the "Product Commissions" separator
            if (cellValue == "Product Commissions") break
            // Add business member names (skip header row)
            if (!cellValue.isNullOrBlank() && cellValue != "Service Provider") {
                serviceBusinessMembers.add(cellValue)
            }
        }

        // Collect all business member names from product section
        val productBusinessMembers = mutableSetOf<String>()
        var inProductSection = false
        for (i in 0..summarySheet.lastRowNum) {
            val row = summarySheet.getRow(i) ?: continue
            val cellValue = try {
                row.getCell(0)?.stringCellValue
            } catch (e: Exception) {
                null
            }
            // Start collecting after Product Commissions header
            if (cellValue == "Service Provider" && inProductSection) {
                continue // Skip the header itself
            }
            if (cellValue == "Product Commissions") {
                inProductSection = true
                continue
            }
            if (inProductSection && !cellValue.isNullOrBlank()) {
                productBusinessMembers.add(cellValue)
            }
        }

        // Only 2 business members should appear in services (servicesOnly + both, NOT productsOnly)
        serviceBusinessMembers.size shouldBe 2
        serviceBusinessMembers shouldNotBe setOf(businessMember2.fullName) // Should not contain products-only member

        // Only 2 business members should appear in products (productsOnly + both, NOT servicesOnly)
        productBusinessMembers.size shouldBe 2
        productBusinessMembers shouldNotBe setOf(businessMember1.fullName) // Should not contain services-only member

        workbook.close()
    }

    "should not create empty detail sections for providers without that category" {
        val businessMember1 = newBusinessMember() // Only services
        val businessMember2 = newBusinessMember() // Only products

        val servicesOnly = newCommissionReportLineItems(
            businessMember = businessMember1,
            minOrders = 1,
            maxOrders = 1,
            minServicesPerOrder = 1,
            maxServicesPerOrder = 1,
            minProductsPerOrder = 0,
            maxProductsPerOrder = 0
        )

        val productsOnly = newCommissionReportLineItems(
            businessMember = businessMember2,
            minOrders = 1,
            maxOrders = 1,
            minServicesPerOrder = 0,
            maxServicesPerOrder = 0,
            minProductsPerOrder = 1,
            maxProductsPerOrder = 1
        )

        val allLineItems = servicesOnly + productsOnly
        val reports = allLineItems.groupBy { it.businessMemberToken }
            .map { (_, items) -> CommissionReport(items, emptyList()) }

        val workbook = reports.toExcelWorkbook()
        val detailsSheet = workbook.sheet("Details")

        // Count how many times each business member name appears
        val memberNames = reports.map { it.businessMemberName }.toSet()
        var servicesOnlyNameCount = 0
        var productsOnlyNameCount = 0

        for (i in 0..detailsSheet.lastRowNum) {
            val row = detailsSheet.getRow(i) ?: continue
            val cell = row.getCell(1) ?: continue
            try {
                val cellValue = cell.stringCellValue
                if (cellValue == servicesOnly.first().businessMemberName) {
                    servicesOnlyNameCount++
                }
                if (cellValue == productsOnly.first().businessMemberName) {
                    productsOnlyNameCount++
                }
            } catch (e: Exception) {
                // Cell might not be a string, skip it
            }
        }

        // Each business member should appear only ONCE (in their relevant section)
        // servicesOnly should appear only in Itemized Services section
        // productsOnly should appear only in Itemized Product Sales section
        servicesOnlyNameCount shouldBe 1
        productsOnlyNameCount shouldBe 1

        workbook.close()
    }
}

